import{_ as e,c as a,o as l,ag as d}from"./chunks/framework.piE7uVCg.js";const g=JSON.parse('{"title":"Galaxy Dimension","description":"","frontmatter":{},"headers":[],"relativePath":"securite/alarme/galaxy.md","filePath":"securite/alarme/galaxy.md"}'),r={name:"securite/alarme/galaxy.md"};function i(n,t,o,s,c,u){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="galaxy-dimension" tabindex="-1"><a href="./readme.html">Galaxy Dimension</a> <a class="header-anchor" href="#galaxy-dimension" aria-label="Permalink to &quot;[Galaxy Dimension](readme.md)&quot;">​</a></h1><h2 id="master-utilisateur-maitre" tabindex="-1">Master (Utilisateur Maitre) <a class="header-anchor" href="#master-utilisateur-maitre" aria-label="Permalink to &quot;Master (Utilisateur Maitre)&quot;">​</a></h2><h3 id="ajouter-un-code" tabindex="-1">Ajouter un code <a class="header-anchor" href="#ajouter-un-code" aria-label="Permalink to &quot;Ajouter un code&quot;">​</a></h3><p><code>code_maitre</code> &gt; <code>ENT</code> &gt; <code>42 (Codes)</code> &gt; <code>ENT</code> &gt;</p><h2 id="acceder-au-mode-installateur" tabindex="-1">Accéder au mode installateur <a class="header-anchor" href="#acceder-au-mode-installateur" aria-label="Permalink to &quot;Accéder au mode installateur&quot;">​</a></h2><p>Pour effectuer des modifications sur le fonctionnement du système il faut accéder au mode installateur. Pour y accéder il faut d&#39;abord l&#39;activer.</p><ol><li><p>Activer le mode<br><code>code_maitre</code> &gt; <code>ENT</code> &gt; <code>48 (Accès installateur)</code> &gt; <code>ENT</code> &gt; <code>ENT</code> &gt; <code>1</code> &gt; <code>ENT</code> &gt; <code>ESC</code> &gt; <code>ESC</code> &gt; <code>ESC</code></p></li><li><p>Entrer dans le mode<br><code>112233</code> &gt; <code>ENT</code></p></li></ol><h2 id="sortir-du-mode-installateur" tabindex="-1">Sortir du mode installateur <a class="header-anchor" href="#sortir-du-mode-installateur" aria-label="Permalink to &quot;Sortir du mode installateur&quot;">​</a></h2><p><code>112233</code> &gt; <code>ESC</code></p><p>Le système va passer en autocontrole et vérifier toute l&#39;installation :</p><ul><li>Si le système ne présente aucun défaut le mode sera quitté</li><li>S&#39;il y a un défaut le système restera dans ce mode</li></ul><p>Le mode sera désactivé automatiquement si un code utilisateur est utilisé.</p><h2 id="changer-de-langue" tabindex="-1">Changer de langue <a class="header-anchor" href="#changer-de-langue" aria-label="Permalink to &quot;Changer de langue&quot;">​</a></h2><p>En mode installateur :</p><p><code>51</code> &gt; <code>17</code> &gt; <code>3</code></p><h2 id="programmation-de-zone" tabindex="-1">Programmation de zone <a class="header-anchor" href="#programmation-de-zone" aria-label="Permalink to &quot;Programmation de zone&quot;">​</a></h2><p>En mode installateur :</p><p><code>52 (Programmation entrées)</code> &gt; Zones</p><table tabindex="0"><thead><tr><th style="text-align:left;">Entree</th><th style="text-align:center;">Numero</th><th style="text-align:left;">champ</th></tr></thead><tbody><tr><td style="text-align:left;">Finale</td><td style="text-align:center;">01</td><td style="text-align:left;">champ</td></tr><tr><td style="text-align:left;">Intrusion</td><td style="text-align:center;">03</td><td style="text-align:left;">champ</td></tr><tr><td style="text-align:left;">Panique</td><td style="text-align:center;">13</td><td style="text-align:left;">champ</td></tr><tr><td style="text-align:left;">Libre</td><td style="text-align:center;">18</td><td style="text-align:left;">champ</td></tr><tr><td style="text-align:left;">Incendie</td><td style="text-align:center;">19</td><td style="text-align:left;">champ</td></tr></tbody></table><p>Exemple : 3005</p><ul><li>3 = numéro de ligne de la centrale</li><li>05 = adresse rio</li><li>7 = zone sur le rio</li></ul><h2 id="rio" tabindex="-1">RIO <a class="header-anchor" href="#rio" aria-label="Permalink to &quot;RIO&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Centrale</th><th style="text-align:center;">Adresses</th></tr></thead><tbody><tr><td style="text-align:left;">GD-48</td><td style="text-align:center;">2-5</td></tr><tr><td style="text-align:left;">GD-520</td><td style="text-align:center;">1-9 et A-F</td></tr></tbody></table><h2 id="exclure-la-ligne-telephonique" tabindex="-1">Exclure la ligne téléphonique <a class="header-anchor" href="#exclure-la-ligne-telephonique" aria-label="Permalink to &quot;Exclure la ligne téléphonique&quot;">​</a></h2><p>En mode installateur :</p><p><code>56 (Communications)</code> -&gt; <code>10 (Défaut de ligne / line fail)</code></p><p>Désactiver 1, 2 et 3</p><h2 id="tempo-de-sortie" tabindex="-1">Tempo de sortie <a class="header-anchor" href="#tempo-de-sortie" aria-label="Permalink to &quot;Tempo de sortie&quot;">​</a></h2><p><code>51 (Paramètres)</code> -&gt; <code>04 (Tempo de sortie)</code> -&gt; 20 -&gt; <code>ENT</code></p><h2 id="tempo-d-entree" tabindex="-1">Tempo d&#39;entrée <a class="header-anchor" href="#tempo-d-entree" aria-label="Permalink to &quot;Tempo d&#39;entrée&quot;">​</a></h2><p><code>51 (Paramètres)</code> -&gt; <code>05 (Tempo d&#39;entrée&#39;)</code> -&gt; 20 -&gt; <code>ENT</code></p><h2 id="menus" tabindex="-1">Menus <a class="header-anchor" href="#menus" aria-label="Permalink to &quot;Menus&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Menu</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;">11</td><td style="text-align:left;">Exclusion de zone</td></tr><tr><td style="text-align:left;">21</td><td style="text-align:left;">Afficher zones</td></tr><tr><td style="text-align:left;">22</td><td style="text-align:left;">Historique</td></tr><tr><td style="text-align:left;">32</td><td style="text-align:left;">Test de sorties</td></tr><tr><td style="text-align:left;">41</td><td style="text-align:left;">Date et heure</td></tr><tr><td style="text-align:left;">42</td><td style="text-align:left;">Codes</td></tr><tr><td style="text-align:left;">47</td><td style="text-align:left;">Acces Distant</td></tr><tr><td style="text-align:left;">48</td><td style="text-align:left;">Accès installateur</td></tr><tr><td style="text-align:left;">41</td><td style="text-align:left;">Date et heure</td></tr><tr><td style="text-align:left;">52</td><td style="text-align:left;">Programmation de zone</td></tr><tr><td style="text-align:left;">52</td><td style="text-align:left;">Programmation de sorties</td></tr><tr><td style="text-align:left;">56</td><td style="text-align:left;">Communications</td></tr><tr><td style="text-align:left;">65</td><td style="text-align:left;">Programme hebdomadaire</td></tr></tbody></table><p><a href="./galaxy_search.html">galaxy</a></p><h2 id="utilisateurs" tabindex="-1">Utilisateurs <a class="header-anchor" href="#utilisateurs" aria-label="Permalink to &quot;Utilisateurs&quot;">​</a></h2><h3 id="activer-le-systeme" tabindex="-1">Activer le système <a class="header-anchor" href="#activer-le-systeme" aria-label="Permalink to &quot;Activer le système&quot;">​</a></h3><p>En généra il suffit de faire :</p><p><code>code</code> + <code>A</code></p><p>S&#39;il y a des groupes dans le système :</p><p><code>code</code> + <code>A</code> + (le numéro des groupe) + <code>ENT</code></p><h3 id="desactiver-le-systeme" tabindex="-1">Désactiver le système <a class="header-anchor" href="#desactiver-le-systeme" aria-label="Permalink to &quot;Désactiver le système&quot;">​</a></h3><p><code>code</code> + <code>ENT</code></p><h3 id="isoler-une-zone" tabindex="-1">Isoler une zone <a class="header-anchor" href="#isoler-une-zone" aria-label="Permalink to &quot;Isoler une zone&quot;">​</a></h3><p><code>code</code> + <code>ENT</code> &gt; <code>11</code><br> Sélectionnez une zone puis appuyez sur <code>#</code> pour l&#39;isoler ou le réactiver</p><h2 id="clavier-voyant-d-alimentation" tabindex="-1">Clavier / Voyant d&#39;alimentation <a class="header-anchor" href="#clavier-voyant-d-alimentation" aria-label="Permalink to &quot;Clavier /  Voyant d&#39;alimentation&quot;">​</a></h2><p>Le voyant d&#39;alimentation vert reste allumé lorsque le clavier est connecté à une alimentation secteur. Une panne de courant est indiquée par un clignotement lent du voyant. Le voyant clignote rapidement si la batterie est faible.tage tombe en dessous du seuil minimum ou si l&#39;un des fusibles du PCB du panneau de commande saute.</p><h2 id="codes" tabindex="-1">Codes <a class="header-anchor" href="#codes" aria-label="Permalink to &quot;Codes&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Utilisateur</th><th style="text-align:center;">Code par défaut</th></tr></thead><tbody><tr><td style="text-align:left;">Installateur</td><td style="text-align:center;">112233</td></tr><tr><td style="text-align:left;">Utilisateur distant</td><td style="text-align:center;">543210</td></tr><tr><td style="text-align:left;">Manager maître</td><td style="text-align:center;">12345</td></tr><tr><td style="text-align:left;">Autorisation</td><td style="text-align:center;">54321</td></tr></tbody></table><h2 id="adresses" tabindex="-1">Adresses <a class="header-anchor" href="#adresses" aria-label="Permalink to &quot;Adresses&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Périphérique</th><th style="text-align:center;">Ligne</th><th style="text-align:center;">GD-48</th><th style="text-align:center;">GD-520</th></tr></thead><tbody><tr><td style="text-align:left;">Clavier</td><td style="text-align:center;">1 <br> 2 <br> 3-4</td><td style="text-align:center;">2-5 <br> - <br> - <br></td><td style="text-align:center;">2-9, B-F <br> 0-9, F <br> 0-6, F</td></tr><tr><td style="text-align:left;">RIO / Alim</td><td style="text-align:center;">1 <br> 2 <br> 3-4</td><td style="text-align:center;">2-5 <br> - <br> - <br></td><td style="text-align:center;">2-9, A-F <br> 0-9, A-F <br> 0-9, A-F <br></td></tr><tr><td style="text-align:left;">Ethernet</td><td style="text-align:center;">1</td><td style="text-align:center;">B</td><td style="text-align:center;">B</td></tr></tbody></table>',50)])])}const m=e(r,[["render",i]]);export{g as __pageData,m as default};
